#include <compare>
#include <iostream>

class Fraction
{
    int m_num{};
    int m_den{ 1 };

public:
    Fraction(int num, int den) : m_num{ num }, m_den{ den } {}

    bool operator==(const Fraction& rhs) const
    {
        return static_cast<long long>(m_num) * rhs.m_den
            == static_cast<long long>(rhs.m_num) * m_den;
    }

    std::strong_ordering operator<=>(const Fraction& rhs) const
    {
        long long lhs_val{ static_cast<long long>(m_num) * rhs.m_den };
        long long rhs_val{ static_cast<long long>(rhs.m_num) * m_den };
        return lhs_val <=> rhs_val;
    }
};

int main()
{
    int n1{}, d1{}, n2{}, d2{};
    std::cin >> n1 >> d1 >> n2 >> d2;

    Fraction f1{ n1, d1 };
    Fraction f2{ n2, d2 };

    std::cout << (f1 == f2 ? "equal" : "not_equal") << '\n';

    auto cmp{ f1 <=> f2 };
    if (cmp < 0)
        std::cout << "less\n";
    else if (cmp > 0)
        std::cout << "greater\n";
    else
        std::cout << "equivalent\n";

    std::cout << (f1 <= f2 ? "true" : "false") << '\n';

    return 0;
}

